import sys
from xml.etree import ElementTree as ET
import xmltodict
import schellow as validate

def read_validate_xml(xml_file):
    with open(xml_file, 'rb') as f:
        xml = f.read()

    try:
        data = ET.fromstring(xml)
    except ET.ParseError as e:
        print("Error parsing XML:", str(e))
        return None

    schema = open('your_xsd_file.xsd').read()
    validator = validate.make_validator(schema)
    validator.validate(data)

    return xmltodict.parse(ET.tostring(data, encoding='unicode', method='xml'))

